return [{
  json: {
    workflow_id: 'CWF-120',
    vein: 'qualification_vein',
    dossier_id: $json.dossier_id || 'TEST-DOSSIER',
    candidates: $json.candidates || [],
    route_id: $json.route_id || 'ROUTE_PHASE1_STANDARD',
    execution_timestamp: new Date().toISOString(),
    qualification_checks: ['demand_fit', 'competition_fit', 'longevity_fit', 'audience_fit', 'budget_fit', 'policy_fit']
  }
}];

const candidates = $json.candidates || [];
const qualified = [];
const rejected = [];

candidates.forEach(c => {
  const checks = {
    demand_fit: c.keyword_count > 5 && c.high_opportunity_keywords && c.high_opportunity_keywords.length > 0,
    competition_fit: true,
    longevity_fit: c.trend === 'RISING' || c.trend === 'STABLE',
    audience_fit: c.estimated_demand === 'HIGH' || c.estimated_demand === 'MEDIUM',
    budget_fit: true,
    policy_fit: true
  };

  const passed = Object.values(checks).filter(v => v).length >= 5;
  if (passed) {
    qualified.push({ ...c, qualification_decision: 'APPROVED_FOR_SCORING', checks: checks });
  } else {
    rejected.push({ ...c, qualification_decision: 'REJECTED', checks: checks, rejection_reasons: Object.entries(checks).filter(([k,v]) => !v).map(([k]) => k) });
  }
});

return [{
  json: {
    ...$json,
    qualified_candidates: qualified,
    rejected_candidates: rejected,
    qualification_summary: {
      total_evaluated: candidates.length,
      approved_for_scoring: qualified.length,
      rejected: rejected.length
    }
  }
}];

const qualified = $json.qualified_candidates || [];
const rejected = $json.rejected_candidates || [];

const qualification_packet = {
  instance_id: 'TFP-' + Date.now(),
  artifact_family: 'topic_finalization_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-120-Topic-Qualification',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: qualified.length > 0 ? 'CREATED' : (rejected.length > 0 ? 'PARTIAL' : 'EMPTY'),
  payload: {
    qualified_count: qualified.length,
    rejected_count: rejected.length,
    qualified_candidates: qualified,
    rejection_records: rejected.map(r => ({ candidate: r.topic_statement, reasons: r.rejection_reasons })),
    decision_summary: {
      all_rejected: rejected.length > 0 && qualified.length === 0,
      needs_broader_discovery: rejected.length > 0 && qualified.length === 0,
      ready_for_scoring: qualified.length > 0
    }
  }
};

return [{ json: qualification_packet }];

try {
  const packet = $json;
  if (!packet.instance_id || !packet.artifact_family) throw new Error('Missing packet fields');
  return [{ json: { validation_result: 'SUCCESS', packet_valid: true, packet: packet } }];
} catch (e) {
  return [{ json: { validation_result: 'ERROR', error: e.message } }];
}

return [{
  json: {
    workflow_id: 'CWF-120',
    execution_status: 'SUCCESS',
    next_workflow: 'CWF-130',
    qualification_packet: $json,
    decision: $json.payload.decision_summary.ready_for_scoring ? 'PROCEED_TO_SCORING' : 'RETURN_TO_DISCOVERY_WITH_NARROWED_SCOPE'
  }
}];
